/**
 * public-api.ts — single entry point for @whoz-oss/agentos-api-client consumers.
 *
 * ## Structure
 *
 * (root)/           → generated by openapi-generator-cli, do NOT import directly
 * src/custom/       → hand-written additions (SSE services, helpers...)
 * src/public-api.ts → YOU ARE HERE: re-exports everything, is the real entryFile
 *
 * ## Why this indirection?
 *
 * openapi-generator-cli regenerates the root files on every `pnpm nx run agentos-api-client:generate-client`.
 * Adding manual exports there would be overwritten. public-api.ts is never touched
 * by the generator, so custom exports are safe here.
 *
 * ## When you add a new custom file
 *
 * 1. Create it in src/custom/
 * 2. Add its export below, in the "Custom" section
 * 3. Do NOT edit generated files manually
 *
 * ## When you regenerate the client
 *
 * Run: pnpm nx run agentos-api-client:generate-client
 * Root generated files will be overwritten — that is expected and safe.
 * public-api.ts and src/custom/ are untouched.
 */

// ── Generated (do not edit directly) ──────────────────────────────────────────
export * from '../../index'

// ── Custom (hand-written, safe from regeneration) ─────────────────────────────
export { CaseEventSseService } from './case-event-sse.service'
